(self.webpackChunkbeary_github_io=self.webpackChunkbeary_github_io||[]).push([[242],{813:(n,s,a)=>{"use strict";a.r(s),a.d(s,{default:()=>p});const t=(0,a(394).uE)('<h1 id="css-基础知识" tabindex="-1"><a class="header-anchor" href="#css-基础知识" aria-hidden="true">#</a> CSS 基础知识</h1><h2 id="渐进增强" tabindex="-1"><a class="header-anchor" href="#渐进增强" aria-hidden="true">#</a> 渐进增强</h2><p>为最小公分母准备可用的内容，然后再为支持新特性的浏览器添加更多交互优化。</p><p>HTML 和 CSS 的实现已经部分内置了这一策略。</p><p>对于 HTML:</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>input</span> <span class="token attr-name">type</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>text<span class="token punctuation">&quot;</span></span> <span class="token punctuation">/&gt;</span></span>\n\n<span class="token comment">&lt;!-- 在不支持 type=&quot;email&quot; 的浏览器会被解析成上面的形式 --&gt;</span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>input</span> <span class="token attr-name">type</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>email<span class="token punctuation">&quot;</span></span> <span class="token punctuation">/&gt;</span></span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>对于 CSS:</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token selector">.overlay</span> <span class="token punctuation">{</span>\n  <span class="token property">background-color</span><span class="token punctuation">:</span> #000<span class="token punctuation">;</span>\n\n  <span class="token comment">/* 如果浏览器支持 rgba ，则覆盖上一条 */</span>\n  <span class="token property">background-color</span><span class="token punctuation">:</span> <span class="token function">rgba</span><span class="token punctuation">(</span>0<span class="token punctuation">,</span> 0<span class="token punctuation">,</span> 0<span class="token punctuation">,</span> 0.8<span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h3 id="厂商前缀" tabindex="-1"><a class="header-anchor" href="#厂商前缀" aria-hidden="true">#</a> 厂商前缀</h3><p>厂商可以为自家浏览器引入实验性特性，并通过其自定义的前缀来识别该特性。</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token selector">.myThing</span> <span class="token punctuation">{</span>\n  <span class="token property">-webkit-transform</span><span class="token punctuation">:</span> <span class="token function">translate</span><span class="token punctuation">(</span>0<span class="token punctuation">,</span> 10px<span class="token punctuation">)</span><span class="token punctuation">;</span>\n  <span class="token property">-moz-transform</span><span class="token punctuation">:</span> <span class="token function">translate</span><span class="token punctuation">(</span>0<span class="token punctuation">,</span> 10px<span class="token punctuation">)</span><span class="token punctuation">;</span>\n  <span class="token property">-ms-transform</span><span class="token punctuation">:</span> <span class="token function">translate</span><span class="token punctuation">(</span>0<span class="token punctuation">,</span> 10px<span class="token punctuation">)</span><span class="token punctuation">;</span>\n\n  <span class="token comment">/* 加一条不带前缀的声明，支持标准属性名称的浏览器 */</span>\n  <span class="token property">transform</span><span class="token punctuation">:</span> <span class="token function">translate</span><span class="token punctuation">(</span>0<span class="token punctuation">,</span> 10px<span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="条件规则与检测" tabindex="-1"><a class="header-anchor" href="#条件规则与检测" aria-hidden="true">#</a> 条件规则与检测</h3><p>使用 <code>@supports</code> 块来判断浏览器是否支持某个 CSS 特性、并提供对应的样式，这个特殊的代码块被称为<strong>条件规则</strong>。</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token atrule"><span class="token rule">@supports</span> <span class="token punctuation">(</span><span class="token property">display</span><span class="token punctuation">:</span> grid<span class="token punctuation">)</span></span> <span class="token punctuation">{</span>\n  <span class="token comment">/* 在支持网格布局的浏览器中要应用的规则 */</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h2 id="语义化-html" tabindex="-1"><a class="header-anchor" href="#语义化-html" aria-hidden="true">#</a> 语义化 HTML</h2><p>在正确的地方使用正确的元素</p><ul><li>确保尽可能多的人能够使用（文本浏览器/屏幕阅读器/盲文点触设备）</li><li>利于机器识别，搜索引擎优化</li><li>有益于 CSS 的组织</li></ul><h3 id="结构化元素" tabindex="-1"><a class="header-anchor" href="#结构化元素" aria-hidden="true">#</a> 结构化元素</h3><p>HTML5 新增一批结构化元素，这些元素是为了在 HTML 文档中创建逻辑性区块。</p><ul><li>section</li><li>header（特定区块的头部）</li><li>footer</li><li>nav（导航组件）</li><li>article（内容）</li><li>aside</li><li>main（在一个 HTML 文档中应该只出现一次）</li></ul><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code><span class="token comment">&lt;!-- 使用新元素之前 --&gt;</span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span> <span class="token attr-name">class</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>article<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span> <span class="token attr-name">class</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>header<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>h1</span><span class="token punctuation">&gt;</span></span>Title<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>h1</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>p</span><span class="token punctuation">&gt;</span></span>Content<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>p</span><span class="token punctuation">&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span>\n\n<span class="token comment">&lt;!-- 使用语义化的新元素后 --&gt;</span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>article</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>header</span><span class="token punctuation">&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>h1</span><span class="token punctuation">&gt;</span></span>Title<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>h1</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>header</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>p</span><span class="token punctuation">&gt;</span></span>Content<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>p</span><span class="token punctuation">&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>article</span><span class="token punctuation">&gt;</span></span>\n\n<span class="token comment">&lt;!-- 更为灵活的用法 --&gt;</span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>article</span> <span class="token attr-name">class</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>post<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>header</span> <span class="token attr-name">class</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>post-header<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>h1</span><span class="token punctuation">&gt;</span></span>Title<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>h1</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>header</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>p</span><span class="token punctuation">&gt;</span></span>Content<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>p</span><span class="token punctuation">&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>article</span><span class="token punctuation">&gt;</span></span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br></div></div><p>上面的第三种做法是最好的，它更据语义化，但增加 CSS 时又不会像第二种方式那样覆盖所有标签的 CSS 。</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token selector">.post</span> <span class="token punctuation">{</span>\n  <span class="token comment">/* 样式 */</span>\n<span class="token punctuation">}</span>\n<span class="token selector">.post-header</span> <span class="token punctuation">{</span>\n  <span class="token comment">/* 其它样式 */</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h3 id="div-和-span" tabindex="-1"><a class="header-anchor" href="#div-和-span" aria-hidden="true">#</a> div 和 span</h3><p>在仅需样式而无需或没有合适语义的情况下使用 <code>div</code> 和 <code>span</code> 。</p><p><code>span</code> 用于给文本流添加样式，但即便是给文本添加样式，也要注意是否存在有合适语义的标签可以使用，例如</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>p</span><span class="token punctuation">&gt;</span></span>请注意，明天早上 <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>time</span><span class="token punctuation">&gt;</span></span>08:00<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>time</span><span class="token punctuation">&gt;</span></span> 在 <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>em</span><span class="token punctuation">&gt;</span></span>东湖广场<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>em</span><span class="token punctuation">&gt;</span></span> 集合，举办 <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>q</span><span class="token punctuation">&gt;</span></span>颁奖大会<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>q</span><span class="token punctuation">&gt;</span></span> ，请务必 <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>strong</span><span class="token punctuation">&gt;</span></span>正装<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>strong</span><span class="token punctuation">&gt;</span></span> 出席。<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>p</span><span class="token punctuation">&gt;</span></span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div>',27),p={render:function(n,s){return t}}},431:(n,s,a)=>{"use strict";a.r(s),a.d(s,{data:()=>t});const t={key:"v-a7937e8a",path:"/css/css.html",title:"CSS 基础知识",lang:"en-US",frontmatter:{title:"CSS 基础知识"},excerpt:"",headers:[{level:2,title:"渐进增强",slug:"渐进增强",children:[{level:3,title:"厂商前缀",slug:"厂商前缀",children:[]},{level:3,title:"条件规则与检测",slug:"条件规则与检测",children:[]}]},{level:2,title:"语义化 HTML",slug:"语义化-html",children:[{level:3,title:"结构化元素",slug:"结构化元素",children:[]},{level:3,title:"div 和 span",slug:"div-和-span",children:[]}]}],filePathRelative:"css/css.md",git:{updatedTime:1625117725e3,contributors:[]}}}}]);